-- Statutory Documents import (Drive-linked, source_url).
-- Mirrors import-ikea-iway-documents.sql / import-fsc-coc-documents.sql / import-iso9001-documents.sql:
-- idempotent, re-runnable.
-- 18 files from Drive folder 'Dun and Bradstreet IKEA Due Diligence' (root-level files only).
-- Excludes 2 subfolders: '5 & 13. PF ESI & employees data' (employee-level HR data) and
-- '6. GSTR-3B & GSTR-1 Returns Jan-25 to Jan-26' (bulk monthly transaction-level tax filings) --
-- same exclusion pattern as HR/Invoices in prior categories.
-- content_text backfilled progressively for AI Copilot grounding, same pattern as prior categories.

on conflict (source_url) do update set
  content_text = excluded.content_text,
  file_size_bytes = excluded.file_size_bytes,
  uploaded_at = excluded.uploaded_at;